// Extract email metadata for downstream nodes
const item = $input.first();
const email = item.json;

return [{
  json: {
    subject: email.subject || '',
    body: email.text || email.html || '',
    fromEmail: email.from?.value?.[0]?.address || email.from || '',
    fromName: email.from?.value?.[0]?.name || '',
    messageId: email.messageId || '',
    inReplyTo: email.inReplyTo || '',
    references: email.references || '',
    date: email.date || new Date().toISOString(),
    rawFrom: JSON.stringify(email.from)
  }
}];

// Parse Ollama JSON response
const raw = $input.first().json.text || $input.first().json.content || '';
let parsed;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { intent: 'OTHER', error: 'Parse failed: ' + raw };
}

// Merge with email data from previous step
const emailData = $('📝 Extract Email Data').first().json;

return [{
  json: {
    ...parsed,
    fromEmail: emailData.fromEmail,
    fromName: emailData.fromName,
    messageId: emailData.messageId,
    inReplyTo: emailData.inReplyTo,
    references: emailData.references,
    originalSubject: emailData.subject,
    originalBody: emailData.body,
    receivedAt: emailData.date
  }
}];

parameters.prompt:
=Based on these search results, identify the booking platform for {{ $('🔧 Parse Claude Response').first().json.restaurant_name }}.

Search results: {{ JSON.stringify($json.organic?.slice(0,5)) }}

Return ONLY a JSON object:
{"platform": "resy|opentable|sevenrooms|tock|yelp|direct|unknown", "booking_url": "direct URL if found or null", "restaurant_confirmed": true/false, "notes": "any relevant info about the restaurant"}

parameters.jsCode:
const raw = $input.first().json.text || $input.first().json.content || '';
let platformData;
try {
  platformData = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  platformData = { platform: 'unknown', booking_url: null };
}

const parsed = $('🔧 Parse Claude Response').first().json;

// Extract OpenTable restaurant ID from booking URL (?rid=12345 or /profile/12345)
let opentableId = null;
if (platformData.platform === 'opentable' && platformData.booking_url) {
  const ridMatch = platformData.booking_url.match(/rid=(\d+)/);
  const profileMatch = platformData.booking_url.match(/\/profile\/(\d+)/);
  opentableId = ridMatch?.[1] || profileMatch?.[1] || null;
}

return [{
  json: {
    ...parsed,
    platform: platformData.platform,
    booking_url: platformData.booking_url,
    restaurant_confirmed: platformData.restaurant_confirmed,
    platform_notes: platformData.notes,
    opentable_id: opentableId
  }
}];

const venueData = $input.first().json;
const parsed = $('🔧 Parse Platform Response').first().json;

// Resy search response can nest the venue ID in several ways
const venue =
  venueData.results?.venues?.[0]?.venue ||
  venueData.hits?.hits?.[0]?._source ||
  venueData.venues?.[0] ||
  {};

const resyVenueId =
  venue.id?.resy ??
  venue.id ??
  venue.venue_id ??
  null;

return [{
  json: {
    ...parsed,
    resy_venue_id: resyVenueId
  }
}];

// Check if slots are available from Resy or OpenTable response
const data = $input.first().json;
const parsed = $('🔧 Parse Platform Response').first().json;

// Resy response structure check
const resySlots = data.results?.venues?.[0]?.slots || [];
// OpenTable response structure check  
const otSlots = data.availability?.times || data.slots || [];

const slots = resySlots.length > 0 ? resySlots : otSlots;
const hasAvailability = slots.length > 0;

return [{
  json: {
    ...parsed,
    hasAvailability,
    availableSlots: slots.slice(0, 5),
    slotCount: slots.length,
    rawAvailabilityResponse: JSON.stringify(data).substring(0, 500)
  }
}];

const bookingResponse = $input.first().json;
const parsed = $('🔧 Parse Platform Response').first().json;

// Extract confirmation number from response
const confirmationNumber = bookingResponse.reservation_id || 
  bookingResponse.resy_token || 
  bookingResponse.data?.[0]?.results?.[0]?.text ||
  'Confirmed';

const bookingSuccessful = !!confirmationNumber && !bookingResponse.error;

return [{
  json: {
    ...parsed,
    bookingSuccessful,
    confirmationNumber,
    bookedSlot: parsed.availableSlots?.[0],
    bookingTimestamp: new Date().toISOString()
  }
}];

