// Collect the email body from whichever Ollama node ran
const nodes = [
  '🦙 Ollama: Write Confirmation Email',
  '🦙 Ollama: Write Unavailable Email', 
  '🦙 Ollama: Write Recommendations',
  '🦙 Ollama: Write Booking Window Reply'
];

let emailBody = '';
for (const nodeName of nodes) {
  try {
    const result = $(nodeName).first();
    if (result && result.json) {
      emailBody = result.json.text || result.json.content || '';
      if (emailBody) break;
    }
  } catch(e) { continue; }
}

if (!emailBody) emailBody = 'Thank you for your message. I have processed your request and will follow up shortly.\n\nBest,\nRésa';

// Get original email data
let fromEmail, originalSubject, messageId;
try {
  const emailData = $('📝 Extract Email Data').first().json;
  fromEmail = emailData.fromEmail;
  originalSubject = emailData.subject;
  messageId = emailData.messageId;
} catch(e) {
  fromEmail = '';
  originalSubject = 'Re: Your Reservation Request';
  messageId = '';
}

const reSubject = originalSubject.startsWith('Re:') ? originalSubject : 'Re: ' + originalSubject;

return [{
  json: {
    toEmail: fromEmail,
    subject: reSubject,
    body: emailBody,
    inReplyTo: messageId
  }
}];

// Filter out watchlist items where the reservation date has passed
const today = new Date();
today.setHours(0,0,0,0);

const items = $input.all();
const active = items.filter(item => {
  const removeDate = item.json['Remove After Date'];
  if (!removeDate) return true;
  const targetDate = new Date(removeDate);
  return targetDate >= today;
});

return active.map(item => ({ json: item.json }));

const availability = $input.first().json;
const watchItem = $('🔧 Filter Expired Items').first().json;

const slots = availability.results?.venues?.[0]?.slots || 
               availability.availability?.times || [];
const hasSlot = slots.length > 0;

return [{
  json: {
    ...watchItem,
    hasSlot,
    availableSlots: slots.slice(0,3),
    checkedAt: new Date().toISOString()
  }
}];

